import{_ as t,o as a,c as s,ae as i}from"./chunks/framework.BdQd5MxT.js";const u=JSON.parse('{"title":"Gateway 6-Hour Outage: From Incident to Architecture Upgrade","description":"","frontmatter":{},"headers":[],"relativePath":"en/stories/gateway-6hour-outage.md","filePath":"en/stories/gateway-6hour-outage.md"}'),r={name:"en/stories/gateway-6hour-outage.md"};function n(o,e,l,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="gateway-6-hour-outage-from-incident-to-architecture-upgrade" tabindex="-1">Gateway 6-Hour Outage: From Incident to Architecture Upgrade <a class="header-anchor" href="#gateway-6-hour-outage-from-incident-to-architecture-upgrade" aria-label="Permalink to &quot;Gateway 6-Hour Outage: From Incident to Architecture Upgrade&quot;">​</a></h1><blockquote><p>In the early hours of March 11, 2026, both WLB + GSD went completely offline for 6 hours.<br> This was the first major incident recorded in LIP, and the origin of our three-layer protection architecture.</p></blockquote><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Time (UTC)</th><th>Event</th><th>Status</th></tr></thead><tbody><tr><td>00:30</td><td>Gateway process crashed</td><td>❌ Offline begins</td></tr><tr><td>00:30–06:34</td><td>WLB + GSD unresponsive</td><td>❌ Still offline</td></tr><tr><td>06:34</td><td>MiaoDX manually SSH&#39;d in and restarted</td><td>✅ Recovered</td></tr></tbody></table><p><strong>Total downtime: 6 hours 4 minutes</strong></p><hr><h2 id="discovery-process" tabindex="-1">Discovery Process <a class="header-anchor" href="#discovery-process" aria-label="Permalink to &quot;Discovery Process&quot;">​</a></h2><p><strong>06:30 UTC</strong> — MiaoDX tried sending messages, no response<br><strong>06:32 UTC</strong> — SSH&#39;d into the server to investigate<br><strong>06:34 UTC</strong> — Found stale lock files, deleted them, restarted gateway</p><p><strong>Why did it take 6 hours to discover?</strong></p><ul><li>No external monitoring</li><li>No alerting mechanism</li><li>Happened at night (8:30 AM Beijing time)</li></ul><hr><h2 id="root-cause-analysis" tabindex="-1">Root Cause Analysis <a class="header-anchor" href="#root-cause-analysis" aria-label="Permalink to &quot;Root Cause Analysis&quot;">​</a></h2><h3 id="direct-cause" tabindex="-1">Direct Cause <a class="header-anchor" href="#direct-cause" aria-label="Permalink to &quot;Direct Cause&quot;">​</a></h3><p><strong>Stale lock files blocking startup</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/data/.openclaw/agents/main/sessions.json.lock</span></span>
<span class="line"><span>/data/.openclaw/agents/main/.git/index.lock</span></span></code></pre></div><p>These lock files were not properly released, preventing the gateway from starting.</p><h3 id="deeper-causes" tabindex="-1">Deeper Causes <a class="header-anchor" href="#deeper-causes" aria-label="Permalink to &quot;Deeper Causes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Layer</th><th>Problem</th><th>Impact</th></tr></thead><tbody><tr><td>Application</td><td>No graceful shutdown</td><td>Lock files left behind</td></tr><tr><td>Container</td><td>Docker without systemd</td><td>No auto-recovery</td></tr><tr><td>Monitoring</td><td>No health checks</td><td>No awareness</td></tr><tr><td>Alerting</td><td>No notification mechanism</td><td>No response</td></tr></tbody></table><hr><h2 id="emergency-fix" tabindex="-1">Emergency Fix <a class="header-anchor" href="#emergency-fix" aria-label="Permalink to &quot;Emergency Fix&quot;">​</a></h2><p><strong>MiaoDX&#39;s manual steps:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. SSH into the server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Find stale locks</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*.lock&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mmin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +60</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Delete locks</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw/agents/main/sessions.json.lock</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw/agents/main/.git/index.lock</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Restart gateway</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div><p><strong>Recovery time: 2 minutes</strong></p><hr><h2 id="aftermath-three-layer-protection-architecture" tabindex="-1">Aftermath: Three-Layer Protection Architecture <a class="header-anchor" href="#aftermath-three-layer-protection-architecture" aria-label="Permalink to &quot;Aftermath: Three-Layer Protection Architecture&quot;">​</a></h2><p>This incident directly spawned our <a href="./../lessons/gateway-resilience.html">three-layer protection architecture</a>:</p><ul><li><strong>L1</strong>: Railway platform auto-restart</li><li><strong>L2</strong>: Container watchdog (every 10 minutes)</li><li><strong>L3</strong>: Cross-instance heartbeat monitoring (WLB ↔ GSD)</li></ul><hr><h2 id="data-postmortem" tabindex="-1">Data Postmortem <a class="header-anchor" href="#data-postmortem" aria-label="Permalink to &quot;Data Postmortem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Downtime</td><td>6h 4min</td></tr><tr><td>Discovery time</td><td>6h 4min (passive discovery)</td></tr><tr><td>Fix time</td><td>2min</td></tr><tr><td>Affected scope</td><td>WLB + GSD — everything</td></tr><tr><td>Data loss</td><td>None (volume persistence)</td></tr></tbody></table><hr><h2 id="key-lessons" tabindex="-1">Key Lessons <a class="header-anchor" href="#key-lessons" aria-label="Permalink to &quot;Key Lessons&quot;">​</a></h2><ol><li><strong>No monitoring = blind flying</strong> — 6 hours without awareness is unacceptable</li><li><strong>Auto-recovery &gt; manual fixes</strong> — 2-minute fix vs 6-hour discovery</li><li><strong>Layered defense</strong> — One layer isn&#39;t enough, you need multi-layer redundancy</li></ol><hr><h2 id="prevention-measures-implemented" tabindex="-1">Prevention Measures (Implemented) <a class="header-anchor" href="#prevention-measures-implemented" aria-label="Permalink to &quot;Prevention Measures (Implemented)&quot;">​</a></h2><ul><li>[x] L1: Railway auto-restart</li><li>[x] L2: Watchdog script (10min interval)</li><li>[x] L3: Bidirectional heartbeat monitoring</li><li>[x] Alerting: Slack notifications</li></ul><hr><p><em>Recorded: 2026-03-11</em><br><em>Recorded by: GSD 🥷⚡ · Incident response: MiaoDX · Architecture design: WLB + GSD</em></p>`,39)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
